package migrate_test

import (
	"database/sql"
	"testing"

	"github.com/oklog/ulid/v2"
	"github.com/stretchr/testify/require"
)

func TestMyBackfill(t *testing.T) {
	id := ulid.Make().String()
	runner{stops: stops{
		{version: 20260320084936, direction: directionUp, action: func(t *testing.T, db *sql.DB) {
			_, err := db.Exec(`INSERT INTO features (namespace,id,created_at,updated_at,name,key) VALUES ('default',$1,NOW(),NOW(),'n','k')`, id)
			require.NoError(t, err)
		}},
		{version: 20260320171954, direction: directionUp, action: func(t *testing.T, db *sql.DB) {
			var v sql.NullString
			require.NoError(t, db.QueryRow(`SELECT meter_id FROM features WHERE id=$1`, id).Scan(&v))
		}},
	}}.Test(t)
}
